-- ----------------------------------------------------------------------------
-- Orders: A customer order. OrderNumber is the PK.
-- ----------------------------------------------------------------------------
CREATE TABLE orders (
  orders_id                           TEXT                 PRIMARY KEY,         -- Synthetic PK = OrderNumber.
  order_number                        TEXT                ,                     -- Human-readable order number (PK source).
  order_date                          DATE                ,                     -- Date the order was placed.
  customer                            TEXT                ,                     -- FK -> Customers.Name (the customer's email).
  total                               NUMERIC                                   -- Order total in dollars.
);
COMMENT ON TABLE orders IS 'A customer order. OrderNumber is the PK.';
COMMENT ON COLUMN orders.orders_id IS 'Synthetic PK = OrderNumber.';
COMMENT ON COLUMN orders.order_number IS 'Human-readable order number (PK source).';
COMMENT ON COLUMN orders.order_date IS 'Date the order was placed.';
COMMENT ON COLUMN orders.customer IS 'FK -> Customers.Name (the customer''s email).';
COMMENT ON COLUMN orders.total IS 'Order total in dollars.';

-- ----------------------------------------------------------------------------
-- Payments: A payment recorded against an order. PaymentNumber is the PK.
-- ----------------------------------------------------------------------------
CREATE TABLE payments (
  payments_id                         TEXT                 PRIMARY KEY,         -- Synthetic PK = PaymentNumber.
  payment_number                      TEXT                ,                     -- Human-readable payment number (PK source).
