);
COMMENT ON TABLE payments IS 'A payment recorded against an order. PaymentNumber is the PK.';
COMMENT ON COLUMN payments.payments_id IS 'Synthetic PK = PaymentNumber.';
COMMENT ON COLUMN payments.payment_number IS 'Human-readable payment number (PK source).';
COMMENT ON COLUMN payments.order_id IS 'FK -> Orders.Name (the order number).';
COMMENT ON COLUMN payments.payment_date IS 'Date the payment was received.';
COMMENT ON COLUMN payments.amount IS 'Payment amount in dollars.';
COMMENT ON COLUMN payments.method IS 'Payment method: card, check, cash, wire, ach.';

-- ----------------------------------------------------------------------------
-- JetModels: Catalog of fighter-jet airframes that flight-control systems are built for. ModelCode is the PK.
-- ----------------------------------------------------------------------------
CREATE TABLE jet_models (
  jet_models_id                       TEXT                 PRIMARY KEY,         -- Synthetic PK = ModelCode.
  model_code                          TEXT                ,                     -- Short model designation, e.g. F-16C.
