);
COMMENT ON TABLE jet_models IS 'Catalog of fighter-jet airframes that flight-control systems are built for. ModelCode is the PK.';
COMMENT ON COLUMN jet_models.jet_models_id IS 'Synthetic PK = ModelCode.';
COMMENT ON COLUMN jet_models.model_code IS 'Short model designation, e.g. F-16C.';
COMMENT ON COLUMN jet_models.manufacturer IS 'Airframe OEM.';
COMMENT ON COLUMN jet_models.generation IS 'Fighter generation (4, 4.5, 5).';

-- ----------------------------------------------------------------------------
-- FlightControlSystems: Flight-control-system product variants. Each variant targets one jet model with a specific control architecture and redundancy level. FCSCode is the PK.
-- ----------------------------------------------------------------------------
CREATE TABLE flight_control_systems (
  flight_control_systems_id           TEXT                 PRIMARY KEY,         -- Synthetic PK = FCSCode.
  fcs_code                            TEXT                ,                     -- Product code, e.g. FCS-F35-FBW4.
  jet_model_id                        TEXT                ,                     -- FK -> JetModels.Name.
  architecture                        TEXT                ,                     -- Control architecture: fly-by-wire, fly-by-light, analog-hybrid.
  redundancy_channels                 NUMERIC             ,                     -- Number of independent control channels (2, 3, or 4).
  unit_price                          NUMERIC                                   -- Per-unit price in $M USD.
);
COMMENT ON TABLE flight_control_systems IS 'Flight-control-system product variants. Each variant targets one jet model with a specific control architecture and redundancy level. FCSCode is the PK.';
COMMENT ON COLUMN flight_control_systems.flight_control_systems_id IS 'Synthetic PK = FCSCode.';
COMMENT ON COLUMN flight_control_systems.fcs_code IS 'Product code, e.g. FCS-F35-FBW4.';
COMMENT ON COLUMN flight_control_systems.jet_model_id IS 'FK -> JetModels.Name.';
COMMENT ON COLUMN flight_control_systems.architecture IS 'Control architecture: fly-by-wire, fly-by-light, analog-hybrid.';
COMMENT ON COLUMN flight_control_systems.redundancy_channels IS 'Number of independent control channels (2, 3, or 4).';
COMMENT ON COLUMN flight_control_systems.unit_price IS 'Per-unit price in $M USD.';

-- ----------------------------------------------------------------------------
-- OrderLines: FCS line items on an order — links Orders to FlightControlSystems with a quantity. LineNumber is the PK.
-- ----------------------------------------------------------------------------
CREATE TABLE order_lines (
  order_lines_id                      TEXT                 PRIMARY KEY,         -- Synthetic PK = LineNumber.
  line_number                         TEXT                ,                     -- Human-readable line code, e.g. OL-3001.
  order_id                            TEXT                ,                     -- FK -> Orders.Name.
  fcs_id                              TEXT                ,                     -- FK -> FlightControlSystems.Name.
  quantity                            NUMERIC                                   -- Number of FCS units on this line.
);
COMMENT ON TABLE order_lines IS 'FCS line items on an order — links Orders to FlightControlSystems with a quantity. LineNumber is the PK.';
COMMENT ON COLUMN order_lines.order_lines_id IS 'Synthetic PK = LineNumber.';
COMMENT ON COLUMN order_lines.line_number IS 'Human-readable line code, e.g. OL-3001.';
COMMENT ON COLUMN order_lines.order_id IS 'FK -> Orders.Name.';
COMMENT ON COLUMN order_lines.fcs_id IS 'FK -> FlightControlSystems.Name.';
COMMENT ON COLUMN order_lines.quantity IS 'Number of FCS units on this line.';

